     1→import { app, BrowserWindow, ipcMain, Tray, Menu, nativeImage } from 'electron';
     2→import { join } from 'path';
     3→import { settingsManager, TranscriptionMode } from '../config/settings';
     4→import { windowManager } from './windowManager';
     5→import { globalShortcutManager } from './globalShortcuts';
     6→// import { audioCapture } from './audioCapture'; // Removed
     7→import { streamingTranscription } from './streamingTranscription';
     8→import { textPostProcessor } from './textPostProcessor';
     9→import { textInjection } from './textInjection';
    10→
    11→let tray: Tray | null = null;
    12→let settingsWindow: BrowserWindow | null = null;
    13→
    14→// Accumulated transcript across speech turns
    15→let currentTranscript = '';
    16→let isStreamingActive = false;
    17→
    18→// Tray pulse animation
    19→let trayPulseInterval: NodeJS.Timeout | null = null;
    20→let trayPulseState = false;
    21→
    22→// ─── Tray Icons ───────────────────────────────────────────
    23→
    24→function createTrayIcon(color: 'default' | 'recording' | 'processing') {
    25→    // 22x22 px template images for macOS menu bar
    26→    const size = 22;
    27→    const canvas = Buffer.alloc(size * size * 4); // RGBA
    28→
    29→    const colors: Record<string, [number, number, number, number]> = {
    30→        default: [180, 180, 180, 200],     // subtle gray
    31→        recording: [0, 220, 255, 255],     // cyan pulse
    32→        processing: [255, 200, 50, 255],   // amber
    33→    };
    34→
    35→    const [r, g, b, a] = colors[color];
    36→
    37→    // Draw a simple filled circle (center dot)
    38→    const cx = size / 2;
    39→    const cy = size / 2;
    40→    const radius = color === 'default' ? 4 : 5;
    41→
    42→    for (let y = 0; y < size; y++) {
    43→        for (let x = 0; x < size; x++) {
    44→            const dist = Math.sqrt((x - cx) ** 2 + (y - cy) ** 2);
    45→            if (dist <= radius) {
    46→                const idx = (y * size + x) * 4;
    47→                canvas[idx] = r;
    48→                canvas[idx + 1] = g;
    49→                canvas[idx + 2] = b;
    50→                canvas[idx + 3] = a;
    51→            }
    52→        }
    53→    }
    54→
    55→    return nativeImage.createFromBuffer(canvas, { width: size, height: size });
    56→}
    57→
    58→function startTrayPulse() {
    59→    if (trayPulseInterval) return;
    60→    trayPulseState = false;
    61→
    62→    trayPulseInterval = setInterval(() => {
    63→        trayPulseState = !trayPulseState;
    64→        if (tray) {
    65→            tray.setImage(createTrayIcon(trayPulseState ? 'recording' : 'default'));
    66→        }
    67→    }, 500);
    68→
    69→    // Immediate first pulse
    70→    if (tray) tray.setImage(createTrayIcon('recording'));
    71→}
    72→
    73→function stopTrayPulse(processing = false) {
    74→    if (trayPulseInterval) {
    75→        clearInterval(trayPulseInterval);
    76→        trayPulseInterval = null;
    77→    }
    78→    if (tray) {
    79→        tray.setImage(createTrayIcon(processing ? 'processing' : 'default'));
    80→    }
    81→}
    82→
    83→// ─── Initialization ───────────────────────────────────────
    84→
    85→async function initialize() {
    86→    settingsManager.initializeFromEnv();
    87→
    88→    if (!settingsManager.hasApiKey()) {
    89→        console.log('No API key configured. User will need to set it in settings.');
    90→    }
    91→
    92→    // Create overlay window (still needed for non-stealth mode)
    93→    await windowManager.createOverlayWindow();
    94→
    95→    // Wire keyboard shortcuts → recording functions
    96→    globalShortcutManager.setCallbacks(
    97→        () => startStreamingSession(),
    98→        () => stopStreamingSession(),
    99→    );
   100→    globalShortcutManager.register();
   101→
   102→    setupIPCHandlers();
   103→    setupStreamingHandlers();
   104→    createSystemTray();
   105→}
   106→
   107→// ─── Streaming Event Handlers ─────────────────────────────
   108→
   109→function setupStreamingHandlers() {
   110→    const isStealth = () => settingsManager.getSetting('stealthMode');
   111→
   112→    // Incremental transcript delta → send to UI if overlay visible
   113→    streamingTranscription.on('delta', (data: { text: string; itemId: string }) => {
   114→        if (!isStealth()) {
   115→            windowManager.sendToRenderer('transcript-delta', {
   116→                text: data.text,
   117→                itemId: data.itemId,
   118→            });
   119→        }
   120→    });
   121→
   122→    // Completed transcript for a speech turn
   123→    streamingTranscription.on('completed', (data: { text: string; itemId: string }) => {
   124→        console.log('[Main] Turn completed:', data.text);
   125→        currentTranscript += (currentTranscript ? ' ' : '') + data.text;
   126→
   127→        if (!isStealth()) {
   128→            windowManager.sendToRenderer('transcript-completed', {
   129→                text: data.text,
   130→                fullText: currentTranscript,
   131→                itemId: data.itemId,
   132→            });
   133→        }
   134→    });
   135→
   136→    streamingTranscription.on('speech_started', () => {
   137→        if (!isStealth()) {
   138→            windowManager.sendToRenderer('recording-state', { state: 'listening' });
   139→        }
   140→    });
   141→
   142→    streamingTranscription.on('speech_stopped', () => {
   143→        if (!isStealth()) {
   144→            windowManager.sendToRenderer('recording-state', { state: 'processing' });
   145→        }
   146→    });
   147→
   148→    streamingTranscription.on('connected', () => {
   149→        console.log('[Main] Streaming connected');
   150→    });
   151→
   152→    streamingTranscription.on('error', (data: { message: string }) => {
   153→        console.error('[Main] Streaming error:', data.message);
   154→        stopTrayPulse();
   155→        if (!isStealth()) {
   156→            windowManager.sendToRenderer('recording-error', { message: data.message });
   157→        }
   158→    });
   159→
   160→    // Audio capture is now handled via IPC from Renderer
   161→}
   162→
   163→// ─── Recording Session Control ────────────────────────────
   164→
   165→async function startStreamingSession() {
   166→    const apiKey = settingsManager.getSetting('apiKey');
   167→    const language = settingsManager.getSetting('language');
   168→    const stealth = settingsManager.getSetting('stealthMode');
   169→
   170→    if (!apiKey) {
   171→        if (!stealth) {
   172→            windowManager.sendToRenderer('recording-error', {
   173→                message: 'No API key configured.',
   174→            });
   175→        }
   176→        return;
   177→    }
   178→
   179→    currentTranscript = '';
   180→    isStreamingActive = true;
   181→
   182→    // Start tray pulse (always, even with overlay)
   183→    startTrayPulse();
   184→
   185→    // Show overlay only if not stealth
   186→    if (!stealth) {
   187→        windowManager.show();
   188→        windowManager.sendToRenderer('recording-state', { state: 'listening' });
   189→    }
   190→
   191→    // Connect WebSocket
   192→    streamingTranscription.connect(apiKey, language);
   193→
   194→    // Start audio capture in Renderer
   195→    windowManager.sendToRenderer('start-capture');
   196→    console.log('[Main] Session started (stealth:', stealth, ')');
   197→}
   198→
   199→async function stopStreamingSession() {
   200→    isStreamingActive = false;
   201→    const stealth = settingsManager.getSetting('stealthMode');
   202→    const mode = settingsManager.getSetting('transcriptionMode') as TranscriptionMode;
   203→
   204→    // Stop audio capture in Renderer
   205→    windowManager.sendToRenderer('stop-capture');
   206→
   207→    // Switch tray to processing
   208→    stopTrayPulse(true);
   209→
   210→    if (!stealth) {
   211→        windowManager.sendToRenderer('recording-state', { state: 'processing' });
   212→    }
   213→
   214→    // Wait for final deltas
   215→    setTimeout(async () => {
   216→        streamingTranscription.disconnect();
   217→
   218→        if (currentTranscript.trim()) {
   219→            try {
   220→                // Post-process based on active mode
   221→                const apiKey = settingsManager.getSetting('apiKey');
   222→                const ppSettings = settingsManager.getSetting('postProcessing');
   223→
   224→                const processedText = await textPostProcessor.processWithMode(
   225→                    currentTranscript.trim(),
   226→                    apiKey,
   227→                    mode,
   228→                    ppSettings,
   229→                );
   230→
   231→                // Inject into active app
   232→                await textInjection.injectText(processedText);
   233→
   234→                console.log(`[Main] Injected (${mode}):`, processedText);
   235→
   236→                if (!stealth) {
   237→                    windowManager.sendToRenderer('transcription-complete', {
   238→                        text: processedText,
   239→                    });
   240→                }
   241→            } catch (error: any) {
   242→                console.error('Injection failed:', error);
   243→                if (!stealth) {
   244→                    windowManager.sendToRenderer('recording-error', {
   245→                        message: 'Failed to inject: ' + error.message,
   246→                    });
   247→                }
   248→            }
   249→        }
   250→
   251→        // Restore tray to default
   252→        stopTrayPulse();
   253→
   254→        // Hide overlay
   255→        if (!stealth) {
   256→            setTimeout(() => windowManager.hide(), 600);
   257→        }
   258→
   259→        currentTranscript = '';
   260→    }, 800);
   261→}
   262→
   263→// ─── IPC Handlers ─────────────────────────────────────────
   264→
   265→function setupIPCHandlers() {
   266→    ipcMain.handle('get-settings', () => settingsManager.getSettings());
   267→    ipcMain.handle('update-settings', (_: any, updates: any) => {
   268→        settingsManager.updateSettings(updates);
   269→        // Rebuild tray menu when settings change (mode might change)
   270→        rebuildTrayMenu();
   271→        return { success: true };
   272→    });
   273→    ipcMain.handle('validate-api-key', (_: any, apiKey: string) => {
   274→        return { valid: settingsManager.validateApiKey(apiKey) };
   275→    });
   276→
   277→    ipcMain.on('start-recording', async () => {
   278→        await startStreamingSession();
   279→    });
   280→    ipcMain.on('stop-recording', async () => {
   281→        await stopStreamingSession();
   282→    });
   283→
   284→    // Audio streaming from Renderer
   285→    ipcMain.on('audio-chunk', (_event, chunk: ArrayBuffer) => {
   286→        if (isStreamingActive) {
   287→            streamingTranscription.sendAudioChunk(Buffer.from(chunk));
   288→        }
   289→    });
   290→
   291→    ipcMain.on('capture-error', async (_event, error: string) => {
   292→        console.error('[Main] Capture error from renderer:', error);
   293→        windowManager.sendToRenderer('recording-error', { message: error });
   294→        await stopStreamingSession();
   295→    });
   296→
   297→    ipcMain.on('open-settings', () => createSettingsWindow());
   298→
   299→    // Shortcut and recording mode updates
   300→    ipcMain.handle('update-shortcut', (_: any, keys: any) => {
   301→        settingsManager.updateSettings({ shortcutKeys: keys });
   302→        globalShortcutManager.updateShortcut(keys);
   303→        rebuildTrayMenu();
   304→        return { success: true };
   305→    });
   306→
   307→    ipcMain.handle('update-recording-mode', (_: any, mode: any) => {
   308→        settingsManager.updateSettings({ recordingMode: mode });
   309→        globalShortcutManager.setRecordingMode(mode);
   310→        rebuildTrayMenu();
   311→        return { success: true };
   312→    });
   313→}
   314→
   315→// ─── System Tray ──────────────────────────────────────────
   316→
   317→function createSystemTray() {
   318→    tray = new Tray(createTrayIcon('default'));
   319→    tray.setToolTip('SPEECHY');
   320→    rebuildTrayMenu();
   321→}
   322→
