   414→// ─── Settings Window ──────────────────────────────────────
   415→
   416→function createSettingsWindow() {
   417→    if (settingsWindow && !settingsWindow.isDestroyed()) {
   418→        settingsWindow.focus();
   419→        return;
   420→    }
   421→
   422→    settingsWindow = new BrowserWindow({
   423→        width: 600,
   424→        height: 700,
   425→        title: 'SPEECHY Settings',
   426→        resizable: false,
   427→        webPreferences: {
   428→            preload: join(__dirname, 'preload.js'),
   429→            contextIsolation: true,
   430→            nodeIntegration: false,
   431→        },
   432→    });
   433→
   434→    if (process.env.NODE_ENV === 'development') {
   435→        settingsWindow.loadURL('http://localhost:5174/settings.html');
   436→    } else {
   437→        settingsWindow.loadFile(join(__dirname, '../renderer/settings.html'));
   438→    }
   439→
   440→    settingsWindow.on('closed', () => {
   441→        settingsWindow = null;
   442→    });
   443→}
   444→
   445→// ─── App Lifecycle ────────────────────────────────────────
   446→
   447→app.whenReady().then(initialize);
   448→
   449→app.on('window-all-closed', (e: Event) => {
   450→    e.preventDefault();
   451→});
   452→
   453→app.on('activate', () => {
   454→    if (BrowserWindow.getAllWindows().length === 0) {
   455→        windowManager.createOverlayWindow();
   456→    }
   457→});
   458→
   459→app.on('before-quit', () => {
   460→    globalShortcutManager.unregister();
   461→    streamingTranscription.disconnect();
   462→    // audioCapture.cleanup(); // Removed
   463→    stopTrayPulse();
   464→});
   465→
   466→const gotTheLock = app.requestSingleInstanceLock();
   467→if (!gotTheLock) {
   468→    app.quit();
   469→} else {
   470→    app.on('second-instance', () => {
   471→        if (settingsWindow && !settingsWindow.isDestroyed()) {
   472→            settingsWindow.focus();
   473→        }
   474→    });
   475→}
