     1→import { EventEmitter } from 'events';
     2→import { AUDIO_SAMPLE_RATE, AUDIO_CHANNELS, PCM_CHUNK_INTERVAL } from '../config/constants';
     3→
     4→/**
     5→ * Audio capture with PCM16 streaming + visualization
     6→ *
     7→ * Emits:
     8→ *   'pcmChunk' → Buffer (raw Int16LE PCM samples, 24kHz mono)
     9→ */
    10→class AudioCapture extends EventEmitter {
    11→    private mediaStream: MediaStream | null = null;
    12→    private audioContext: AudioContext | null = null;
    13→    private analyser: AnalyserNode | null = null;
    14→    private scriptProcessor: ScriptProcessorNode | null = null;
    15→    private visualizationData: Uint8Array = new Uint8Array(new ArrayBuffer(128));
    16→    private isRecording = false;
    17→
    18→    // Fallback: also keep MediaRecorder for non-streaming path
    19→    private mediaRecorder: MediaRecorder | null = null;
    20→    private audioChunks: Blob[] = [];
    21→
    22→    /**
    23→     * Start audio recording with PCM streaming
    24→     */
    25→    async startRecording(streaming: boolean = true): Promise<void> {
    26→        try {
    27→            // Request microphone access
    28→            this.mediaStream = await navigator.mediaDevices.getUserMedia({
    29→                audio: {
    30→                    channelCount: AUDIO_CHANNELS,
    31→                    sampleRate: AUDIO_SAMPLE_RATE,
    32→                    echoCancellation: true,
    33→                    noiseSuppression: true,
    34→                    autoGainControl: true,
    35→                },
    36→            });
    37→
    38→            // Setup audio context for visualization + PCM extraction
    39→            this.audioContext = new AudioContext({ sampleRate: AUDIO_SAMPLE_RATE });
    40→            const source = this.audioContext.createMediaStreamSource(this.mediaStream);
    41→
    42→            // Analyser for UI visualization
    43→            this.analyser = this.audioContext.createAnalyser();
    44→            this.analyser.fftSize = 256;
    45→            this.analyser.smoothingTimeConstant = 0.8;
    46→            source.connect(this.analyser);
    47→
    48→            if (streaming) {
    49→                // ScriptProcessor to capture raw PCM samples for streaming
    50→                // Buffer size ≈ 100ms at 24kHz → 2400 samples, round to 4096
    51→                const bufferSize = 4096;
    52→                this.scriptProcessor = this.audioContext.createScriptProcessor(bufferSize, 1, 1);
    53→
    54→                this.scriptProcessor.onaudioprocess = (event: AudioProcessingEvent) => {
    55→                    if (!this.isRecording) return;
    56→
    57→                    const inputData = event.inputBuffer.getChannelData(0); // Float32 [-1, 1]
    58→
    59→                    // Convert Float32 → Int16LE PCM
    60→                    const pcmBuffer = Buffer.alloc(inputData.length * 2);
    61→                    for (let i = 0; i < inputData.length; i++) {
    62→                        // Clamp and convert
    63→                        const sample = Math.max(-1, Math.min(1, inputData[i]));
    64→                        pcmBuffer.writeInt16LE(Math.round(sample * 32767), i * 2);
    65→                    }
    66→
    67→                    this.emit('pcmChunk', pcmBuffer);
    68→                };
    69→
    70→                source.connect(this.scriptProcessor);
    71→                this.scriptProcessor.connect(this.audioContext.destination);
    72→            } else {
    73→                // Non-streaming fallback: use MediaRecorder
    74→                this.mediaRecorder = new MediaRecorder(this.mediaStream, {
    75→                    mimeType: 'audio/webm;codecs=opus',
    76→                });
    77→                this.audioChunks = [];
    78→                this.mediaRecorder.ondataavailable = (event) => {
    79→                    if (event.data.size > 0) {
    80→                        this.audioChunks.push(event.data);
    81→                    }
    82→                };
    83→                this.mediaRecorder.start();
    84→            }
    85→
    86→            this.isRecording = true;
    87→
    88→            // Start visualization data updates
    89→            this.updateVisualizationData();
    90→
    91→            console.log(`Audio recording started (streaming: ${streaming})`);
    92→        } catch (error) {
    93→            console.error('Failed to start audio recording:', error);
    94→            throw new Error('Microphone access denied or unavailable');
    95→        }
    96→    }
    97→
    98→    /**
    99→     * Stop recording. In non-streaming mode returns audio blob; in streaming mode returns null
   100→     */
   101→    async stopRecording(): Promise<Blob | null> {
   102→        this.isRecording = false;
   103→
   104→        // Stop PCM streaming processor
   105→        if (this.scriptProcessor) {
   106→            this.scriptProcessor.disconnect();
   107→            this.scriptProcessor = null;
   108→        }
   109→
   110→        // Non-streaming: return recorded blob
   111→        if (this.mediaRecorder && this.mediaRecorder.state !== 'inactive') {
   112→            return new Promise((resolve) => {
   113→                this.mediaRecorder!.onstop = () => {
   114→                    const audioBlob = new Blob(this.audioChunks, { type: 'audio/webm' });
   115→                    this.cleanup();
   116→                    resolve(audioBlob);
   117→                };
   118→                this.mediaRecorder!.stop();
   119→            });
   120→        }
   121→
   122→        this.cleanup();
   123→        return null;
   124→    }
   125→
   126→    /**
   127→     * Update visualization data from analyser
   128→     */
   129→    private updateVisualizationData(): void {
   130→        if (!this.analyser) return;
   131→
   132→        const update = () => {
   133→            if (!this.analyser) return;
   134→
   135→            // @ts-ignore - TypeScript strict type checking issue with Web Audio API types
   136→            this.analyser.getByteFrequencyData(this.visualizationData);
   137→
   138→            if (this.isRecording) {
   139→                requestAnimationFrame(update);
   140→            }
   141→        };
   142→
   143→        update();
   144→    }
   145→
   146→    /**
   147→     * Get current visualization data
   148→     */
   149→    getVisualizationData(): Uint8Array {
   150→        return this.visualizationData;
   151→    }
   152→
   153→    /**
   154→     * Cleanup resources
   155→     */
   156→    cleanup(): void {
   157→        if (this.mediaStream) {
   158→            this.mediaStream.getTracks().forEach((track) => track.stop());
   159→            this.mediaStream = null;
   160→        }
   161→
   162→        if (this.scriptProcessor) {
   163→            this.scriptProcessor.disconnect();
   164→            this.scriptProcessor = null;
   165→        }
   166→
   167→        if (this.audioContext) {
   168→            this.audioContext.close();
   169→            this.audioContext = null;
   170→        }
   171→
   172→        this.analyser = null;
   173→        this.mediaRecorder = null;
   174→        this.audioChunks = [];
   175→        this.isRecording = false;
   176→    }
   177→}
   178→
   179→export const audioCapture = new AudioCapture();
   180→

