     4→// Legacy Whisper API constants (kept for fallback; primary path is Realtime streaming)
     5→const WHISPER_API_URL = 'https://api.openai.com/v1/audio/transcriptions';
     6→const WHISPER_MODEL = 'gpt-4o-transcribe';
     7→
     8→/**
     9→ * Whisper API response interface
    10→ */
    11→interface WhisperResponse {
    12→    text: string;
    13→}
    14→
    15→/**
    16→ * OpenAI Whisper API integration
    17→ */
    18→class WhisperAPI {
    19→    /**
    20→     * Transcribe audio using Whisper API
    21→     */
    22→    async transcribe(audioBlob: Blob, apiKey: string, language: string = 'auto'): Promise<WhisperResponse> {
    23→        try {
    24→            // Convert Blob to Buffer for FormData
    25→            const arrayBuffer = await audioBlob.arrayBuffer();
    26→            const buffer = Buffer.from(arrayBuffer);
    27→
    28→            // Prepare form data
    29→            const formData = new FormData();
    30→            formData.append('file', buffer, {
    31→                filename: 'audio.webm',
    32→                contentType: 'audio/webm',
    33→            });
    34→            formData.append('model', WHISPER_MODEL);
    35→
    36→            // Only add language if not auto-detect
    37→            if (language !== 'auto') {
    38→                formData.append('language', language);
    39→            }
    40→
    41→            // Make API request
    42→            const response = await axios.post<WhisperResponse>(WHISPER_API_URL, formData, {
    43→                headers: {
    44→                    ...formData.getHeaders(),
    45→                    'Authorization': `Bearer ${apiKey}`,
    46→                },
    47→                timeout: 30000, // 30 second timeout
    48→            });
    49→
    50→            return response.data;
    51→        } catch (error: any) {
    52→            console.error('Whisper API error:', error);
    53→
    54→            // Handle specific errors
    55→            if (error.response) {
    56→                const status = error.response.status;
    57→                if (status === 401) {
    58→                    throw new Error('Invalid API key');
    59→                } else if (status === 429) {
    60→                    throw new Error('Rate limit exceeded. Please try again later.');
    61→                } else if (status === 413) {
    62→                    throw new Error('Audio file too large');
    63→                }
    64→            } else if (error.code === 'ENOTFOUND') {
    65→                throw new Error('Network error. Please check your internet connection.');
    66→            } else if (error.code === 'ETIMEDOUT') {
    67→                throw new Error('Request timeout. Please try again.');
    68→            }
    69→
    70→            throw new Error('Transcription failed. Please try again.');
    71→        }
    72→    }
    73→
    74→    /**
    75→     * Test API key validity
    76→     */
    77→    async testApiKey(apiKey: string): Promise<boolean> {
    78→        try {
    79→            // Create a tiny silent audio blob for testing
    80→            const testBlob = new Blob(['test'], { type: 'audio/webm' });
    81→            await this.transcribe(testBlob, apiKey);
    82→            return true;
    83→        } catch {
    84→            return false;
    85→        }
    86→    }
    87→}
