    17→const MODE_PROMPTS: Record<TranscriptionMode, string> = {
    18→    raw: '', // no processing
    19→    clean: '', // local processing only, no GPT
    20→    rewrite: `Tu es un assistant d'écriture professionnel. Reformule le texte dicté en prose professionnelle, claire et structurée. Conserve le sens exact. Corrige la grammaire, la ponctuation, et retire les hésitations. Si le texte est un email, formate-le comme tel avec salutation et conclusion. Réponds UNIQUEMENT avec le texte reformulé, sans commentaire.`,
    21→};
    22→
    23→/**
