     5→/**
     6→ * Manages the overlay window
     7→ */
     8→class WindowManager {
     9→    private overlayWindow: BrowserWindow | null = null;
    10→
    11→    /**
    12→     * Create the frameless overlay window
    13→     */
    14→    async createOverlayWindow(): Promise<void> {
    15→        const { width: screenWidth, height: screenHeight } = screen.getPrimaryDisplay().workAreaSize;
    16→
    17→        this.overlayWindow = new BrowserWindow({
    18→            width: OVERLAY_SIZE.WIDTH,
    19→            height: OVERLAY_SIZE.HEIGHT,
    20→            x: Math.floor((screenWidth - OVERLAY_SIZE.WIDTH) / 2),
    21→            y: Math.floor((screenHeight - OVERLAY_SIZE.HEIGHT) / 2),
    22→            frame: false,
    23→            transparent: true,
    24→            alwaysOnTop: true,
    25→            resizable: false,
    26→            movable: false,
    27→            minimizable: false,
    28→            maximizable: false,
    29→            closable: false,
    30→            skipTaskbar: true,
    31→            hasShadow: false,
    32→            focusable: false,
    33→            show: false, // Start hidden
    34→            webPreferences: {
    35→                preload: join(__dirname, 'preload.js'),
    36→                contextIsolation: true,
    37→                nodeIntegration: false,
    38→            },
    39→        });
    40→
    41→        // Set window to be click-through when idle
    42→        this.overlayWindow.setIgnoreMouseEvents(true, { forward: true });
    43→
    44→        // Load renderer
    45→        if (process.env.NODE_ENV === 'development') {
    46→            await this.overlayWindow.loadURL('http://localhost:5174');
    47→            // this.overlayWindow.webContents.openDevTools({ mode: 'detach' });
    48→        } else {
    49→            await this.overlayWindow.loadFile(join(__dirname, '../renderer/index.html'));
    50→        }
    51→
    52→        // Handle window close
    53→        this.overlayWindow.on('closed', () => {
    54→            this.overlayWindow = null;
    55→        });
    56→    }
    57→
    58→    /**
    59→     * Show overlay window with fade-in
    60→     */
    61→    show(): void {
    62→        if (this.overlayWindow && !this.overlayWindow.isDestroyed()) {
    63→            this.overlayWindow.show();
    64→            this.sendToRenderer('window-visibility', { visible: true });
    65→        }
    66→    }
    67→
    68→    /**
    69→     * Hide overlay window with fade-out
    70→     */
    71→    hide(): void {
    72→        if (this.overlayWindow && !this.overlayWindow.isDestroyed()) {
    73→            // Let CSS handle fade-out animation, then hide
    74→            this.sendToRenderer('window-visibility', { visible: false });
    75→            setTimeout(() => {
    76→                if (this.overlayWindow && !this.overlayWindow.isDestroyed()) {
    77→                    this.overlayWindow.hide();
    78→                }
    79→            }, 200); // Match CSS transition duration
    80→        }
    81→    }
    82→
    83→    /**
    84→     * Send message to renderer process
    85→     */
    86→    sendToRenderer(channel: string, data?: any): void {
    87→        if (this.overlayWindow && !this.overlayWindow.isDestroyed()) {
    88→            this.overlayWindow.webContents.send(channel, data);
    89→        }
    90→    }
    91→
    92→    /**
    93→     * Get overlay window instance
    94→     */
    95→    getWindow(): BrowserWindow | null {
    96→        return this.overlayWindow;
    97→    }
    98→
    99→    /**
   100→     * Cleanup
   101→     */
   102→    destroy(): void {
   103→        if (this.overlayWindow && !this.overlayWindow.isDestroyed()) {
   104→            this.overlayWindow.destroy();
   105→            this.overlayWindow = null;
   106→        }
   107→    }
   108→}
   109→
   110→export const windowManager = new WindowManager();
