    80→    },
    81→};
    82→
    83→/**
    84→ * Encrypted settings store
    85→ */
    86→const store = new Store<AppSettings>({
    87→    name: 'speechy-config',
    88→    defaults: defaultSettings,
    89→    encryptionKey: 'speechy-secure-key-v1',
    90→});
    91→
    92→/**
    93→ * Settings management functions
    94→ */
    95→export const settingsManager = {
    96→    getSettings(): AppSettings {
    97→        return store.store;
    98→    },
    99→
   100→    getSetting<K extends keyof AppSettings>(key: K): AppSettings[K] {
   101→        return store.get(key);
   102→    },
   103→
   104→    updateSettings(updates: Partial<AppSettings>): void {
   105→        Object.entries(updates).forEach(([key, value]) => {
   106→            store.set(key as keyof AppSettings, value);
   107→        });
   108→    },
   109→
   110→    setSetting<K extends keyof AppSettings>(key: K, value: AppSettings[K]): void {
   111→        store.set(key, value);
   112→    },
   113→
   114→    initializeFromEnv(): void {
   115→        const storedKey = store.get('apiKey');
   116→        const envKey = process.env.OPENAI_API_KEY;
   117→
   118→        if ((!storedKey || storedKey === '') && envKey && envKey.startsWith('sk-')) {
   119→            store.set('apiKey', envKey);
   120→            console.log('API key loaded from .env file');
   121→        }
   122→
   123→        const envLang = process.env.WHISPER_LANGUAGE;
   124→        if (envLang && store.get('language') === 'auto') {
   125→            store.set('language', envLang);
   126→        }
   127→    },
   128→
   129→    hasApiKey(): boolean {
   130→        const apiKey = store.get('apiKey');
   131→        return apiKey !== '' && apiKey.startsWith('sk-');
   132→    },
   133→
   134→    validateApiKey(apiKey: string): boolean {
   135→        return apiKey.startsWith('sk-') && apiKey.length > 20;
   136→    },
   137→
   138→    reset(): void {
   139→        store.clear();
   140→    },
   141→};
