    19→
    20→        const updateAudioData = () => {
    21→            const data = audioCapture.getVisualizationData();
    22→            // Create a copy to trigger React re-render
    23→            setAudioData(new Uint8Array(data));
    24→            animationFrameRef.current = requestAnimationFrame(updateAudioData);
    25→        };
    26→
    27→        updateAudioData();
    28→
    29→        return () => {
    30→            if (animationFrameRef.current) {
    31→                cancelAnimationFrame(animationFrameRef.current);
    32→            }
    33→        };
    34→    }, [isRecording]);
    35→
    36→    return audioData;
