import { useEffect } from 'react';
import { OverlayWindow } from './components/OverlayWindow';
import { useRecordingState } from './hooks/useRecordingState';
import { useAudioVisualization } from './hooks/useAudioVisualization';
import { audioCapture } from './audioCapture';

/**
 * Main application component
 */
export default function App() {
    const {
        state, mode, errorMessage, isVisible,
        recordingDuration, liveTranscript, finalTranscript,
    } = useRecordingState();
    const audioData = useAudioVisualization(state === 'listening');

    useEffect(() => {
        // Handle start capture command from Main
        window.electronAPI.onStartCapture(async () => {
            try {
                console.log('Received start-capture command');
                await audioCapture.startRecording();
            } catch (error) {
                console.error('Failed to start recording:', error);
                const msg = error instanceof Error ? error.message : 'Microphone access denied';
                window.electronAPI.sendCaptureError(msg);
            }
        });

        // Handle stop capture command from Main
        window.electronAPI.onStopCapture(() => {
            console.log('Received stop-capture command');
            audioCapture.stopRecording();
        });

        // Setup streaming callback
        audioCapture.setOnPcmChunk((chunk) => {
            window.electronAPI.sendAudioChunk(chunk);
        });
    }, []);

    return (
        <OverlayWindow
            state={state}
            mode={mode}
            audioData={audioData}
            duration={recordingDuration}
            errorMessage={errorMessage}
            isVisible={isVisible}
            liveTranscript={liveTranscript}
            finalTranscript={finalTranscript}
        />
    );
}

