import Store from 'electron-store';
import { config } from 'dotenv';
import { resolve } from 'path';
import { DEFAULT_SHORTCUTS } from './constants';

// Load .env file from project root
config({ path: resolve(__dirname, '../../.env') });

/**
 * Transcription output modes
 */
export type TranscriptionMode = 'raw' | 'clean' | 'rewrite';

/**
 * Recording mode types
 */
export type RecordingMode = 'push-to-talk' | 'toggle';

/**
 * Keyboard shortcut configuration
 */
export interface ShortcutKeys {
    modifiers: ('command' | 'control' | 'shift' | 'alt')[];
    key: string; // e.g., 'Space', 'R', 'T'
}

/**
 * Application settings interface
 */
export interface AppSettings {
    apiKey: string;
    language: string;
    shortcut: string; // legacy field, kept for backward compatibility
    recordingMode: RecordingMode;
    shortcutKeys: ShortcutKeys;
    microphoneDeviceId?: string;
    stealthMode: boolean; // true = no overlay, menu bar pulse only
    transcriptionMode: TranscriptionMode;
    theme: {
        accentColor: string;
    };
    overlay: {
        width: number;
        height: number;
    };
    postProcessing: {
        autoCapitalize: boolean;
        fixPunctuation: boolean;
        removeFillers: boolean;
        systemPrompt: string;
    };
}

/**
 * Default settings - loads API key from .env if available
 */
const defaultSettings: AppSettings = {
    apiKey: process.env.OPENAI_API_KEY || '',
    language: process.env.WHISPER_LANGUAGE || 'auto',
    shortcut: DEFAULT_SHORTCUTS[process.platform as keyof typeof DEFAULT_SHORTCUTS] || DEFAULT_SHORTCUTS.darwin,
    recordingMode: 'push-to-talk',
    shortcutKeys: {
        modifiers: process.platform === 'darwin' ? ['command', 'shift'] : ['control', 'shift'],
        key: 'Space',
    },
    stealthMode: true, // stealth by default — zero friction
    transcriptionMode: 'clean',
    theme: {
        accentColor: '#00d9ff',
    },
    overlay: {
        width: 340,
        height: 380,
    },
    postProcessing: {
        autoCapitalize: true,
        fixPunctuation: true,
        removeFillers: true,
        systemPrompt: '',
    },
};

/**
 * Encrypted settings store
 */
const store = new Store<AppSettings>({
    name: 'speechy-config',
    defaults: defaultSettings,
    encryptionKey: 'speechy-secure-key-v1',
});

/**
 * Settings management functions
 */
export const settingsManager = {
    getSettings(): AppSettings {
        return store.store;
    },

    getSetting<K extends keyof AppSettings>(key: K): AppSettings[K] {
        return store.get(key);
    },

    updateSettings(updates: Partial<AppSettings>): void {
        Object.entries(updates).forEach(([key, value]) => {
            store.set(key as keyof AppSettings, value);
        });
    },

    setSetting<K extends keyof AppSettings>(key: K, value: AppSettings[K]): void {
        store.set(key, value);
    },

    initializeFromEnv(): void {
        const storedKey = store.get('apiKey');
        const envKey = process.env.OPENAI_API_KEY;

        if ((!storedKey || storedKey === '') && envKey && envKey.startsWith('sk-')) {
            store.set('apiKey', envKey);
            console.log('API key loaded from .env file');
        }

        const envLang = process.env.WHISPER_LANGUAGE;
        if (envLang && store.get('language') === 'auto') {
            store.set('language', envLang);
        }
    },

    hasApiKey(): boolean {
        const apiKey = store.get('apiKey');
        return apiKey !== '' && apiKey.startsWith('sk-');
    },

    validateApiKey(apiKey: string): boolean {
        return apiKey.startsWith('sk-') && apiKey.length > 20;
    },

    reset(): void {
        store.clear();
    },
};

/**
 * Application-wide constants
 */

export const APP_NAME = 'SPEECHY';
export const APP_VERSION = '1.0.0';

// OpenAI Realtime API (Streaming Transcription)
export const REALTIME_API_URL = 'wss://api.openai.com/v1/realtime?intent=transcription';
export const REALTIME_TRANSCRIPTION_MODEL = 'gpt-4o-transcribe';

// Audio settings — Realtime API requires 24kHz mono PCM16
export const AUDIO_SAMPLE_RATE = 24000;
export const AUDIO_CHANNELS = 1;
export const AUDIO_BIT_DEPTH = 16;

// PCM streaming chunk interval (ms)
export const PCM_CHUNK_INTERVAL = 100;

// Keyboard shortcuts (platform-specific defaults)
export const DEFAULT_SHORTCUTS = {
    darwin: 'CommandOrControl+Shift+Space',
    win32: 'Control+Shift+Space',
    linux: 'Control+Shift+Space',
};

// Double-tap detection threshold (ms)
export const DOUBLE_TAP_THRESHOLD = 300;

// UI animation durations (ms)
export const ANIMATION_DURATION = {
    FADE_IN: 150,
    FADE_OUT: 150,
    PULSE: 1000,
    WAVE: 60,
};

// Overlay window settings
export const OVERLAY_SIZE = {
    WIDTH: 320,
    HEIGHT: 380,
};

// Recording limits
export const MAX_RECORDING_DURATION = 120000; // 120 seconds

// Supported languages
export const SUPPORTED_LANGUAGES = [
    { code: 'auto', name: 'Auto-detect' },
    { code: 'en', name: 'English' },
    { code: 'fr', name: 'French' },
    { code: 'es', name: 'Spanish' },
    { code: 'de', name: 'German' },
    { code: 'it', name: 'Italian' },
    { code: 'pt', name: 'Portuguese' },
    { code: 'ja', name: 'Japanese' },
    { code: 'ko', name: 'Korean' },
    { code: 'zh', name: 'Chinese' },
];

// Recording states
export enum RecordingState {
    IDLE = 'idle',
    LISTENING = 'listening',
    PROCESSING = 'processing',
    ERROR = 'error',
}

// Recording modes
export enum RecordingMode {
    PUSH_TO_TALK = 'push-to-talk',
    TOGGLE = 'toggle',
}

