import { useState, useEffect, useRef } from 'react';

export type RecordingState = 'idle' | 'listening' | 'processing' | 'error';
export type RecordingMode = 'push-to-talk' | 'toggle';

interface RecordingStateHook {
    state: RecordingState;
    mode: RecordingMode;
    errorMessage: string;
    isVisible: boolean;
    recordingDuration: number;
    liveTranscript: string;
    finalTranscript: string;
}

/**
 * Hook to manage recording state + live streaming transcript from Electron IPC
 */
export function useRecordingState(): RecordingStateHook {
    const [state, setState] = useState<RecordingState>('idle');
    const [mode, setMode] = useState<RecordingMode>('push-to-talk');
    const [errorMessage, setErrorMessage] = useState('');
    const [isVisible, setIsVisible] = useState(false);
    const [recordingDuration, setRecordingDuration] = useState(0);

    // Streaming transcript state
    const [liveTranscript, setLiveTranscript] = useState('');
    const [finalTranscript, setFinalTranscript] = useState('');
    const currentDeltaText = useRef('');

    useEffect(() => {
        if (!window.electronAPI) return;

        // Listen for shortcut pressed → start recording
        window.electronAPI.onShortcutPressed(() => {
            setState('listening');
            setIsVisible(true);
            setErrorMessage('');
            setRecordingDuration(0);
            setLiveTranscript('');
            setFinalTranscript('');
            currentDeltaText.current = '';
        });

        // Listen for shortcut released → stop recording
        window.electronAPI.onShortcutReleased(() => {
            setState('processing');
        });

        // Recording state changes
        window.electronAPI.onRecordingState((data: any) => {
            if (data.state) {
                setState(data.state as RecordingState);
            }
        });

        // Streaming transcript: incremental delta
        window.electronAPI.onTranscriptDelta((data) => {
            currentDeltaText.current += data.text;
            setLiveTranscript(currentDeltaText.current);
        });

        // Streaming transcript: completed turn
        window.electronAPI.onTranscriptCompleted((data) => {
            setFinalTranscript(data.fullText);
            setLiveTranscript('');
            currentDeltaText.current = '';
        });

        // Errors
        window.electronAPI.onRecordingError((data: any) => {
            setState('error');
            setErrorMessage(data.message || 'An error occurred');
            setTimeout(() => {
                setIsVisible(false);
                setState('idle');
            }, 2000);
        });

        // Transcription complete → hide overlay
        window.electronAPI.onTranscriptionComplete(() => {
            setState('idle');
            setIsVisible(false);
            setRecordingDuration(0);
            setLiveTranscript('');
            setFinalTranscript('');
            currentDeltaText.current = '';
        });
    }, []);

    // Timer for recording duration
    useEffect(() => {
        if (state === 'listening') {
            const interval = setInterval(() => {
                setRecordingDuration((prev) => prev + 1);
            }, 1000);
            return () => clearInterval(interval);
        }
    }, [state]);

    return {
        state,
        mode,
        errorMessage,
        isVisible,
        recordingDuration,
        liveTranscript,
        finalTranscript,
    };
}

