   317→            document.getElementById('toggleMode').checked = true;
   318→            currentRecordingMode = 'toggle';
   319→            updateRadioVisuals();
   320→        });
   321→
   322→        function updateRadioVisuals() {
   323→            document.getElementById('pushToTalkOption').classList.toggle('active',
   324→                document.getElementById('pushToTalk').checked);
   325→            document.getElementById('toggleOption').classList.toggle('active',
   326→                document.getElementById('toggleMode').checked);
   327→        }
   328→
   329→        // Shortcut recorder
   330→        const shortcutInput = document.getElementById('shortcutInput');
   331→        let isRecordingShortcut = false;
   332→
   333→        shortcutInput.addEventListener('click', () => {
   334→            isRecordingShortcut = true;
   335→            shortcutInput.classList.add('recording');
   336→            shortcutInput.value = 'Press any key combination...';
   337→            shortcutInput.focus();
   338→        });
   339→
   340→        shortcutInput.addEventListener('blur', () => {
   341→            if (isRecordingShortcut) {
   342→                isRecordingShortcut = false;
   343→                shortcutInput.classList.remove('recording');
   344→                updateShortcutDisplay();
   345→            }
   346→        });
