   349→            if (!isRecordingShortcut) return;
   350→
   351→            e.preventDefault();
   352→            e.stopPropagation();
   353→
   354→            // Build modifiers array
   355→            const modifiers = [];
   356→            if (e.metaKey) modifiers.push('command');
   357→            if (e.ctrlKey) modifiers.push('control');
   358→            if (e.shiftKey) modifiers.push('shift');
   359→            if (e.altKey) modifiers.push('alt');
   360→
   361→            // Get the key (filter out modifier keys)
   362→            let key = e.key;
   363→            if (['Meta', 'Control', 'Shift', 'Alt'].includes(key)) {
   364→                return; // Only modifiers pressed, wait for actual key
   365→            }
   366→
   367→            // Normalize key names
   368→            if (key === ' ') key = 'Space';
   369→            if (key.length === 1) key = key.toUpperCase();
