import { BrowserWindow, screen } from 'electron';
import { join } from 'path';
import { OVERLAY_SIZE } from '../config/constants';

/**
 * Manages the overlay window
 */
class WindowManager {
    private overlayWindow: BrowserWindow | null = null;

    /**
     * Create the frameless overlay window
     */
    async createOverlayWindow(): Promise<void> {
        const { width: screenWidth, height: screenHeight } = screen.getPrimaryDisplay().workAreaSize;

        this.overlayWindow = new BrowserWindow({
            width: OVERLAY_SIZE.WIDTH,
            height: OVERLAY_SIZE.HEIGHT,
            x: Math.floor((screenWidth - OVERLAY_SIZE.WIDTH) / 2),
            y: Math.floor((screenHeight - OVERLAY_SIZE.HEIGHT) / 2),
            frame: false,
            transparent: true,
            alwaysOnTop: true,
            resizable: false,
            movable: false,
            minimizable: false,
            maximizable: false,
            closable: false,
            skipTaskbar: true,
            hasShadow: false,
            focusable: false,
            show: false, // Start hidden
            webPreferences: {
                preload: join(__dirname, 'preload.js'),
                contextIsolation: true,
                nodeIntegration: false,
            },
        });

        // Set window to be click-through when idle
        this.overlayWindow.setIgnoreMouseEvents(true, { forward: true });

        // Load renderer
        if (process.env.NODE_ENV === 'development') {
            await this.overlayWindow.loadURL('http://localhost:5174');
            // this.overlayWindow.webContents.openDevTools({ mode: 'detach' });
        } else {
            await this.overlayWindow.loadFile(join(__dirname, '../renderer/index.html'));
        }

        // Handle window close
        this.overlayWindow.on('closed', () => {
            this.overlayWindow = null;
        });
    }

    /**
     * Show overlay window with fade-in
     */
    show(): void {
        if (this.overlayWindow && !this.overlayWindow.isDestroyed()) {
            this.overlayWindow.show();
            this.sendToRenderer('window-visibility', { visible: true });
        }
    }

    /**
     * Hide overlay window with fade-out
     */
    hide(): void {
        if (this.overlayWindow && !this.overlayWindow.isDestroyed()) {
            // Let CSS handle fade-out animation, then hide
            this.sendToRenderer('window-visibility', { visible: false });
            setTimeout(() => {
                if (this.overlayWindow && !this.overlayWindow.isDestroyed()) {
                    this.overlayWindow.hide();
                }
            }, 200); // Match CSS transition duration
        }
    }

    /**
     * Send message to renderer process
     */
    sendToRenderer(channel: string, data?: any): void {
        if (this.overlayWindow && !this.overlayWindow.isDestroyed()) {
            this.overlayWindow.webContents.send(channel, data);
        }
    }

    /**
     * Get overlay window instance
     */
    getWindow(): BrowserWindow | null {
        return this.overlayWindow;
    }

    /**
     * Cleanup
     */
    destroy(): void {
        if (this.overlayWindow && !this.overlayWindow.isDestroyed()) {
            this.overlayWindow.destroy();
            this.overlayWindow = null;
        }
    }
}

export const windowManager = new WindowManager();

