import { contextBridge, ipcRenderer, IpcRendererEvent } from 'electron';

/**
 * Preload script - exposes safe IPC methods to renderer
 */
contextBridge.exposeInMainWorld('electronAPI', {
    // Settings
    getSettings: () => ipcRenderer.invoke('get-settings'),
    updateSettings: (updates: any) => ipcRenderer.invoke('update-settings', updates),
    validateApiKey: (apiKey: string) => ipcRenderer.invoke('validate-api-key', apiKey),
    updateShortcut: (keys: any) => ipcRenderer.invoke('update-shortcut', keys),
    updateRecordingMode: (mode: string) => ipcRenderer.invoke('update-recording-mode', mode),

    // Recording control
    startRecording: () => ipcRenderer.send('start-recording'),
    stopRecording: () => ipcRenderer.send('stop-recording'),

    // Audio streaming (Renderer -> Main)
    sendAudioChunk: (chunk: ArrayBuffer) => ipcRenderer.send('audio-chunk', chunk),
    sendCaptureError: (error: string) => ipcRenderer.send('capture-error', error),

    // Capture control (Main -> Renderer)
    onStartCapture: (callback: () => void) => ipcRenderer.on('start-capture', callback),
    onStopCapture: (callback: () => void) => ipcRenderer.on('stop-capture', callback),

    // Settings window
    openSettings: () => ipcRenderer.send('open-settings'),

    // Event listeners
    onRecordingState: (callback: (data: any) => void) => {
        ipcRenderer.on('recording-state', (_event: IpcRendererEvent, data: any) => callback(data));
    },
    onRecordingError: (callback: (data: any) => void) => {
        ipcRenderer.on('recording-error', (_event: IpcRendererEvent, data: any) => callback(data));
    },
    onTranscriptionComplete: (callback: (data: any) => void) => {
        ipcRenderer.on('transcription-complete', (_event: IpcRendererEvent, data: any) => callback(data));
    },
    onShortcutPressed: (callback: () => void) => {
        ipcRenderer.on('shortcut-pressed', callback);
    },
    onShortcutReleased: (callback: () => void) => {
        ipcRenderer.on('shortcut-released', callback);
    },
    onToggleRecording: (callback: () => void) => {
        ipcRenderer.on('toggle-recording', callback);
    },

    // Streaming transcription events
    onTranscriptDelta: (callback: (data: { text: string; itemId: string }) => void) => {
        ipcRenderer.on('transcript-delta', (_event: IpcRendererEvent, data: { text: string; itemId: string }) => callback(data));
    },
    onTranscriptCompleted: (callback: (data: { text: string; fullText: string; itemId: string }) => void) => {
        ipcRenderer.on('transcript-completed', (_event: IpcRendererEvent, data: { text: string; fullText: string; itemId: string }) => callback(data));
    },
});

// TypeScript declarations for window.electronAPI
declare global {
    interface Window {
        electronAPI: {
            getSettings: () => Promise<any>;
            updateSettings: (updates: any) => Promise<{ success: boolean }>;
            validateApiKey: (apiKey: string) => Promise<{ valid: boolean }>;
            startRecording: () => void;
            stopRecording: () => void;
            getAudioData: () => Promise<Uint8Array>;
            openSettings: () => void;
            onRecordingState: (callback: (data: any) => void) => void;
            onRecordingError: (callback: (data: any) => void) => void;
            onTranscriptionComplete: (callback: (data: any) => void) => void;
            onShortcutPressed: (callback: () => void) => void;
            onShortcutReleased: (callback: () => void) => void;
            onToggleRecording: (callback: () => void) => void;
            onTranscriptDelta: (callback: (data: { text: string; itemId: string }) => void) => void;
            onTranscriptCompleted: (callback: (data: { text: string; fullText: string; itemId: string }) => void) => void;
        };
    }
}

/**
 * Application-wide constants
 */

export const APP_NAME = 'SPEECHY';
export const APP_VERSION = '1.0.0';

// OpenAI Realtime API (Streaming Transcription)
export const REALTIME_API_URL = 'wss://api.openai.com/v1/realtime?intent=transcription';
export const REALTIME_TRANSCRIPTION_MODEL = 'gpt-4o-transcribe';

// Audio settings — Realtime API requires 24kHz mono PCM16
export const AUDIO_SAMPLE_RATE = 24000;
export const AUDIO_CHANNELS = 1;
export const AUDIO_BIT_DEPTH = 16;

// PCM streaming chunk interval (ms)
export const PCM_CHUNK_INTERVAL = 100;

// Keyboard shortcuts (platform-specific defaults)
export const DEFAULT_SHORTCUTS = {
    darwin: 'CommandOrControl+Shift+Space',
    win32: 'Control+Shift+Space',
    linux: 'Control+Shift+Space',
};

// Double-tap detection threshold (ms)
export const DOUBLE_TAP_THRESHOLD = 300;

// UI animation durations (ms)
export const ANIMATION_DURATION = {
    FADE_IN: 150,
    FADE_OUT: 150,
    PULSE: 1000,
    WAVE: 60,
};

// Overlay window settings
export const OVERLAY_SIZE = {
    WIDTH: 320,
    HEIGHT: 380,
};

// Recording limits
export const MAX_RECORDING_DURATION = 120000; // 120 seconds

// Supported languages
export const SUPPORTED_LANGUAGES = [
    { code: 'auto', name: 'Auto-detect' },
    { code: 'en', name: 'English' },
    { code: 'fr', name: 'French' },
    { code: 'es', name: 'Spanish' },
    { code: 'de', name: 'German' },
    { code: 'it', name: 'Italian' },
    { code: 'pt', name: 'Portuguese' },
    { code: 'ja', name: 'Japanese' },
    { code: 'ko', name: 'Korean' },
    { code: 'zh', name: 'Chinese' },
];

// Recording states
export enum RecordingState {
    IDLE = 'idle',
    LISTENING = 'listening',
    PROCESSING = 'processing',
    ERROR = 'error',
}

// Recording modes
export enum RecordingMode {
    PUSH_TO_TALK = 'push-to-talk',
    TOGGLE = 'toggle',
}

