import { uIOhook, UiohookKey } from 'uiohook-napi';
import { settingsManager, ShortcutKeys, RecordingMode } from '../config/settings';
import { windowManager } from './windowManager';

type RecordingCallback = () => void;

/**
 * Global keyboard shortcut manager with configurable shortcuts and modes.
 */
class GlobalShortcutManager {
    private isRecording = false;
    private recordingMode: RecordingMode = 'push-to-talk';
    private shortcutKeys: ShortcutKeys = {
        modifiers: ['command', 'shift'],
        key: 'Space',
    };

    private onStartCallback: RecordingCallback | null = null;
    private onStopCallback: RecordingCallback | null = null;

    /**
     * Set callbacks for recording start/stop
     */
    setCallbacks(onStart: RecordingCallback, onStop: RecordingCallback): void {
        this.onStartCallback = onStart;
        this.onStopCallback = onStop;
    }

    /**
     * Register global keyboard hooks with current settings
     */
    register(): void {
        try {
            // Load settings
            const settings = settingsManager.getSettings();
            this.recordingMode = settings.recordingMode;
            this.shortcutKeys = settings.shortcutKeys;

            uIOhook.on('keydown', (event) => this.handleKeyDown(event));
            uIOhook.on('keyup', (event) => this.handleKeyUp(event));
            uIOhook.start();
            console.log(`Global shortcuts registered: ${this.getShortcutString()}, mode: ${this.recordingMode}`);
        } catch (error) {
            console.error('Failed to register global shortcuts:', error);
        }
    }

    /**
     * Unregister global hooks
     */
    unregister(): void {
        try {
            uIOhook.stop();
            console.log('Global shortcuts unregistered');
        } catch (error) {
            console.error('Failed to unregister shortcuts:', error);
        }
    }

    /**
     * Update shortcut keys dynamically
     */
    updateShortcut(keys: ShortcutKeys): void {
        this.unregister();
        this.shortcutKeys = keys;
        this.register();
        console.log(`Shortcut updated to: ${this.getShortcutString()}`);
    }

    /**
     * Update recording mode dynamically
     */
    setRecordingMode(mode: RecordingMode): void {
        this.recordingMode = mode;
        console.log(`Recording mode set to: ${mode}`);

        // Notify renderer
        windowManager.sendToRenderer('recording-mode-changed', {
            mode: mode,
        });
    }

    /**
     * Get current shortcut as human-readable string
     */
    getShortcutString(): string {
        const modStr = this.shortcutKeys.modifiers
            .map(m => m.charAt(0).toUpperCase() + m.slice(1))
            .join('+');
        return `${modStr}+${this.shortcutKeys.key}`;
    }

    /**
     * Check if the current key event matches the configured shortcut
     */
    private isShortcutPressed(event: any): boolean {
        // Check that all configured modifiers are pressed
        const hasCommand = this.shortcutKeys.modifiers.includes('command') ? event.metaKey : !event.metaKey;
        const hasControl = this.shortcutKeys.modifiers.includes('control') ? event.ctrlKey : !event.ctrlKey;
        const hasShift = this.shortcutKeys.modifiers.includes('shift') ? event.shiftKey : !event.shiftKey;
        const hasAlt = this.shortcutKeys.modifiers.includes('alt') ? event.altKey : !event.altKey;

        // Map key name to keycode (simplified mapping)
        const keyMatch = this.matchesKey(event.keycode, this.shortcutKeys.key);

        return hasCommand && hasControl && hasShift && hasAlt && keyMatch;
    }

    /**
     * Match keycode to key name using UiohookKey enum
     */
    private matchesKey(keycode: number, keyName: string): boolean {
        const keyMap: Record<string, number> = {
            'Space': UiohookKey.Space,
            'A': UiohookKey.A,
            'B': UiohookKey.B,
            'C': UiohookKey.C,
            'D': UiohookKey.D,
            'E': UiohookKey.E,
            'F': UiohookKey.F,
            'G': UiohookKey.G,
            'H': UiohookKey.H,
            'I': UiohookKey.I,
            'J': UiohookKey.J,
            'K': UiohookKey.K,
            'L': UiohookKey.L,
            'M': UiohookKey.M,
            'N': UiohookKey.N,
            'O': UiohookKey.O,
            'P': UiohookKey.P,
            'Q': UiohookKey.Q,
            'R': UiohookKey.R,
            'S': UiohookKey.S,
            'T': UiohookKey.T,
            'U': UiohookKey.U,
            'V': UiohookKey.V,
            'W': UiohookKey.W,
            'X': UiohookKey.X,
            'Y': UiohookKey.Y,
            'Z': UiohookKey.Z,
            // Digit keys: UiohookKey uses numeric property names (0-9)
            '0': (UiohookKey as any)[0], '1': (UiohookKey as any)[1],
            '2': (UiohookKey as any)[2], '3': (UiohookKey as any)[3],
            '4': (UiohookKey as any)[4], '5': (UiohookKey as any)[5],
            '6': (UiohookKey as any)[6], '7': (UiohookKey as any)[7],
            '8': (UiohookKey as any)[8], '9': (UiohookKey as any)[9],
            'F1': UiohookKey.F1,
            'F2': UiohookKey.F2,
            'F3': UiohookKey.F3,
            'F4': UiohookKey.F4,
            'F5': UiohookKey.F5,
            'F6': UiohookKey.F6,
            'F7': UiohookKey.F7,
            'F8': UiohookKey.F8,
            'F9': UiohookKey.F9,
            'F10': UiohookKey.F10,
            'F11': UiohookKey.F11,
            'F12': UiohookKey.F12,
        };
        return keyMap[keyName] === keycode;
    }

    private handleKeyDown(event: any): void {
        if (!this.isShortcutPressed(event)) return;

        if (this.recordingMode === 'push-to-talk') {
            // Push-to-talk: start on keydown
            if (!this.isRecording) {
                this.startRecording();
            }
        } else {
            // Toggle mode: toggle on keydown
            if (this.isRecording) {
                this.stopRecording();
            } else {
                this.startRecording();
            }
        }
    }

    private handleKeyUp(event: any): void {
        if (!this.isShortcutPressed(event)) return;

        // Only stop on keyup in push-to-talk mode
        if (this.recordingMode === 'push-to-talk' && this.isRecording) {
            this.stopRecording();
        }
    }

    private startRecording(): void {
        this.isRecording = true;
        windowManager.sendToRenderer('shortcut-pressed', {});

        if (this.onStartCallback) {
            this.onStartCallback();
        }
    }

    private stopRecording(): void {
        this.isRecording = false;
        windowManager.sendToRenderer('shortcut-released', {});

        if (this.onStopCallback) {
            this.onStopCallback();
        }
    }
}

