.overlay-container {
    width: 100vw;
    height: 100vh;
    display: flex;
    align-items: center;
    justify-content: center;
    transition: opacity var(--transition-medium);
}

.overlay-container.visible {
    opacity: 1;
}

.overlay-container.hidden {
    opacity: 0;
    pointer-events: none;
}

.overlay-window {
    position: relative;
    width: 340px;
    min-height: 280px;
    max-height: 420px;
    display: flex;
    align-items: center;
    justify-content: center;
    background: var(--bg-overlay);
    border-radius: 28px;
    backdrop-filter: blur(20px);
    box-shadow: var(--shadow-overlay);
    transition: all var(--transition-medium);
    overflow: hidden;
}

/* Glow ring effect */
.glow-ring {
    position: absolute;
    top: -2px;
    left: -2px;
    right: -2px;
    bottom: -2px;
    border-radius: 30px;
    background: linear-gradient(135deg,
            var(--accent-primary),
            transparent,
            var(--accent-primary));
    opacity: 0;
    transition: opacity var(--transition-medium);
    z-index: -1;
}

.overlay-window.listening .glow-ring {
    opacity: 0.6;
    animation: glowPulse 2s ease-in-out infinite;
}

.overlay-window.error .glow-ring {
    background: linear-gradient(135deg,
            var(--accent-error),
            transparent,
            var(--accent-error));
    opacity: 0.8;
}

/* Accent border */
.accent-border {
    position: absolute;
    top: 0;
    left: 0;
    right: 0;
    bottom: 0;
    border-radius: 28px;
    border: 2px solid transparent;
    pointer-events: none;
}

.overlay-window.listening .accent-border {
    border-color: rgba(0, 217, 255, 0.3);
}

.overlay-window.processing .accent-border {
    border-color: rgba(160, 164, 184, 0.3);
}

.overlay-window.error .accent-border {
    border-color: rgba(255, 71, 87, 0.5);
}

/* Content */
.overlay-content {
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    gap: var(--spacing-md, 12px);
    padding: var(--spacing-lg, 20px);
    width: 100%;
}

/* State-specific styles */
.overlay-window.idle {
    transform: scale(0.95);
    opacity: 0.8;
}

.overlay-window.listening {
    transform: scale(1);
    opacity: 1;
}

.overlay-window.processing {
    transform: scale(1);
    opacity: 1;
}

.overlay-window.error {
    transform: scale(1.02);
    opacity: 1;
}

/* ========================= */
/* Live Transcript Preview   */
/* ========================= */

.transcript-preview {
    width: 100%;
    max-height: 100px;
    overflow-y: auto;
    padding: 10px 14px;
    border-radius: 14px;
    background: rgba(0, 0, 0, 0.35);
    border: 1px solid rgba(255, 255, 255, 0.06);
    backdrop-filter: blur(6px);
    scrollbar-width: thin;
    scrollbar-color: rgba(255, 255, 255, 0.15) transparent;
    animation: fadeInUp 0.25s ease-out;
}

.transcript-preview::-webkit-scrollbar {
    width: 4px;
}

.transcript-preview::-webkit-scrollbar-thumb {
    background: rgba(255, 255, 255, 0.15);
    border-radius: 2px;
}

.transcript-text {
    font-family: var(--font-system, 'Inter', -apple-system, sans-serif);
    font-size: 13px;
    line-height: 1.5;
    color: rgba(255, 255, 255, 0.92);
    word-break: break-word;
}

.transcript-final {
    color: rgba(255, 255, 255, 0.95);
}

.transcript-live {
    color: rgba(0, 217, 255, 0.85);
    font-style: italic;
}

.transcript-cursor {
    display: inline-block;
    color: var(--accent-primary, #00d9ff);
    animation: cursorBlink 0.8s step-end infinite;
    margin-left: 1px;
    font-weight: 300;
}

@keyframes cursorBlink {

    0%,
    100% {
        opacity: 1;
    }

    50% {
        opacity: 0;
    }
}

@keyframes fadeInUp {
    from {
        opacity: 0;
        transform: translateY(6px);
    }

    to {
        opacity: 1;
        transform: translateY(0);
    }
}

