import React, { useEffect, useRef } from 'react';
import './AudioVisualizer.css';

interface AudioVisualizerProps {
    audioData: Uint8Array;
    state: 'idle' | 'listening' | 'processing' | 'error';
}

/**
 * Circular audio visualizer component
 */
export function AudioVisualizer({ audioData, state }: AudioVisualizerProps) {
    const canvasRef = useRef<HTMLCanvasElement>(null);

    useEffect(() => {
        const canvas = canvasRef.current;
        if (!canvas) return;

        const ctx = canvas.getContext('2d');
        if (!ctx) return;

        // Set canvas size
        const size = 200;
        canvas.width = size;
        canvas.height = size;

        const centerX = size / 2;
        const centerY = size / 2;
        const radius = 60;

        // Clear canvas
        ctx.clearRect(0, 0, size, size);

        if (state === 'idle') {
            // Draw idle state: simple pulsing dot
            drawIdleState(ctx, centerX, centerY, radius);
        } else if (state === 'listening') {
            // Draw listening state: circular waveform
            drawWaveform(ctx, centerX, centerY, radius, audioData);
        } else if (state === 'processing') {
            // Draw processing state: spinning loader
            drawProcessing(ctx, centerX, centerY, radius);
        } else if (state === 'error') {
            // Draw error state: red pulsing
            drawError(ctx, centerX, centerY, radius);
        }
    }, [audioData, state]);

    return <canvas ref={canvasRef} className="audio-visualizer" />;
}

/**
 * Draw idle state
 */
function drawIdleState(ctx: CanvasRenderingContext2D, x: number, y: number, radius: number) {
    const time = Date.now() / 1000;
    const pulseScale = 1 + Math.sin(time * 2) * 0.1;

    ctx.beginPath();
    ctx.arc(x, y, radius * 0.3 * pulseScale, 0, Math.PI * 2);
    ctx.fillStyle = 'rgba(0, 217, 255, 0.3)';
    ctx.fill();

    // Glow
    ctx.shadowBlur = 20;
    ctx.shadowColor = '#00d9ff';
}

/**
 * Draw circular waveform
 */
function drawWaveform(
    ctx: CanvasRenderingContext2D,
    x: number,
    y: number,
    radius: number,
    audioData: Uint8Array
) {
    const bars = 64; // Number of bars around the circle
    const barWidth = 3;
    const gap = 2;

    for (let i = 0; i < bars; i++) {
        const dataIndex = Math.floor((i / bars) * audioData.length);
        const amplitude = audioData[dataIndex] / 255; // Normalize to 0-1

        const angle = (i / bars) * Math.PI * 2 - Math.PI / 2;
        const barHeight = amplitude * 40 + 5;

        const x1 = x + Math.cos(angle) * radius;
        const y1 = y + Math.sin(angle) * radius;
        const x2 = x + Math.cos(angle) * (radius + barHeight);
        const y2 = y + Math.sin(angle) * (radius + barHeight);

        ctx.beginPath();
        ctx.moveTo(x1, y1);
        ctx.lineTo(x2, y2);
        ctx.lineWidth = barWidth;
        ctx.strokeStyle = `rgba(0, 217, 255, ${0.5 + amplitude * 0.5})`;
        ctx.shadowBlur = 10;
        ctx.shadowColor = '#00d9ff';
        ctx.stroke();
    }

    // Center circle
    ctx.beginPath();
    ctx.arc(x, y, radius * 0.6, 0, Math.PI * 2);
    ctx.fillStyle = 'rgba(10, 10, 15, 0.8)';
    ctx.fill();
}

/**
 * Draw processing spinner
 */
function drawProcessing(ctx: CanvasRenderingContext2D, x: number, y: number, radius: number) {
    const time = Date.now() / 1000;
    const rotation = time * 2; // Speed of rotation

    for (let i = 0; i < 12; i++) {
        const angle = (i / 12) * Math.PI * 2 + rotation;
        const opacity = (i / 12);

        const x1 = x + Math.cos(angle) * radius * 0.6;
        const y1 = y + Math.sin(angle) * radius * 0.6;
        const x2 = x + Math.cos(angle) * radius;
        const y2 = y + Math.sin(angle) * radius;

        ctx.beginPath();
        ctx.moveTo(x1, y1);
        ctx.lineTo(x2, y2);
        ctx.lineWidth = 3;
        ctx.strokeStyle = `rgba(0, 217, 255, ${opacity})`;
        ctx.stroke();
    }
}

/**
 * Draw error state
 */
function drawError(ctx: CanvasRenderingContext2D, x: number, y: number, radius: number) {
    const time = Date.now() / 1000;
    const pulseScale = 1 + Math.sin(time * 4) * 0.15;

    // Outer pulse
    ctx.beginPath();
    ctx.arc(x, y, radius * pulseScale, 0, Math.PI * 2);
    ctx.strokeStyle = 'rgba(255, 71, 87, 0.6)';
    ctx.lineWidth = 3;
    ctx.shadowBlur = 20;
    ctx.shadowColor = '#ff4757';
    ctx.stroke();

    // Inner circle
    ctx.beginPath();
    ctx.arc(x, y, radius * 0.5, 0, Math.PI * 2);
    ctx.fillStyle = 'rgba(255, 71, 87, 0.3)';
    ctx.fill();
}

