     1→import axios from 'axios';
     2→import { TranscriptionMode } from '../config/settings';
     3→
     4→export interface PostProcessingOptions {
     5→    autoCapitalize: boolean;
     6→    fixPunctuation: boolean;
     7→    removeFillers: boolean;
     8→    systemPrompt: string;
     9→}
    10→
    11→// Common filler words/phrases to strip
    12→const FILLER_PATTERNS = [
    13→    /\b(um|uh|er|ah|euh|bah|ben|bref|genre|en fait|du coup|voilà|quoi|tu vois|you know|basically|actually|literally|I mean|so yeah|right|like)\b/gi,
    14→];
    15→
    16→// System prompts for each transcription mode
    17→const MODE_PROMPTS: Record<TranscriptionMode, string> = {
    18→    raw: '', // no processing
    19→    clean: '', // local processing only, no GPT
    20→    rewrite: `Tu es un assistant d'écriture professionnel. Reformule le texte dicté en prose professionnelle, claire et structurée. Conserve le sens exact. Corrige la grammaire, la ponctuation, et retire les hésitations. Si le texte est un email, formate-le comme tel avec salutation et conclusion. Réponds UNIQUEMENT avec le texte reformulé, sans commentaire.`,
    21→};
    22→
    23→/**
    24→ * Text post-processing pipeline for transcriptions.
    25→ * Supports 3 modes: raw, clean, rewrite
    26→ */
    27→class TextPostProcessor {
    28→    /**
    29→     * Process transcript based on mode
    30→     */
    31→    async processWithMode(
    32→        text: string,
    33→        apiKey: string,
    34→        mode: TranscriptionMode,
    35→        options: Partial<PostProcessingOptions> = {},
    36→    ): Promise<string> {
    37→        if (!text.trim()) return text;
    38→
    39→        // RAW mode: return as-is
    40→        if (mode === 'raw') {
    41→            return text.trim();
    42→        }
    43→
    44→        // CLEAN mode: local processing only
    45→        if (mode === 'clean') {
    46→            return this.processLocal(text, options);
    47→        }
    48→
    49→        // REWRITE mode: local clean + GPT rewrite
    50→        if (mode === 'rewrite') {
    51→            const cleaned = this.processLocal(text, options);
    52→            const prompt = options.systemPrompt || MODE_PROMPTS.rewrite;
    53→            if (prompt && apiKey) {
    54→                try {
    55→                    return await this.gptFormat(cleaned, apiKey, prompt);
    56→                } catch (err) {
    57→                    console.error('[TextPostProcessor] GPT rewrite failed, using cleaned text:', err);
    58→                    return cleaned;
    59→                }
    60→            }
    61→            return cleaned;
    62→        }
    63→
    64→        return text.trim();
    65→    }
    66→
    67→    /**
    68→     * Legacy method — backwards compat
    69→     */
    70→    async process(
    71→        text: string,
    72→        apiKey: string,
    73→        options: Partial<PostProcessingOptions> = {},
    74→    ): Promise<string> {
    75→        return this.processLocal(text, options);
    76→    }
    77→
    78→    /**
    79→     * Local (no API call) post-processing
    80→     */
    81→    private processLocal(text: string, options: Partial<PostProcessingOptions> = {}): string {
    82→        let result = text.trim();
    83→
    84→        if (options.removeFillers !== false) {
    85→            result = this.removeFillers(result);
    86→        }
    87→
    88→        if (options.autoCapitalize !== false) {
    89→            result = this.autoCapitalize(result);
    90→        }
    91→
    92→        if (options.fixPunctuation !== false) {
    93→            result = this.fixPunctuation(result);
    94→        }
    95→
    96→        return result;
    97→    }
    98→
    99→    private removeFillers(text: string): string {
   100→        let result = text;
   101→        for (const pattern of FILLER_PATTERNS) {
   102→            result = result.replace(pattern, '');
   103→        }
   104→        return result.replace(/\s{2,}/g, ' ').trim();
   105→    }
   106→
   107→    private autoCapitalize(text: string): string {
   108→        let result = text.charAt(0).toUpperCase() + text.slice(1);
   109→        result = result.replace(/([.!?]\s+)([a-z])/g, (_, punct, letter) => {
   110→            return punct + letter.toUpperCase();
   111→        });
   112→        return result;
   113→    }
   114→
   115→    private fixPunctuation(text: string): string {
   116→        let result = text;
   117→        result = result.replace(/\s+([.,!?;:])/g, '$1');
   118→        result = result.replace(/([.,!?;:])([A-Za-zÀ-ÿ])/g, '$1 $2');
   119→        if (result.length > 0 && !/[.!?]$/.test(result)) {
   120→            result += '.';
   121→        }
   122→        return result;
   123→    }
   124→
   125→    private async gptFormat(
   126→        text: string,
   127→        apiKey: string,
   128→        systemPrompt: string,
   129→    ): Promise<string> {
   130→        const response = await axios.post(
   131→            'https://api.openai.com/v1/chat/completions',
   132→            {
   133→                model: 'gpt-4o-mini',
   134→                messages: [
   135→                    { role: 'system', content: systemPrompt },
   136→                    { role: 'user', content: text },
   137→                ],
   138→                temperature: 0.3,
   139→                max_tokens: 2048,
   140→            },
   141→            {
   142→                headers: {
   143→                    Authorization: `Bearer ${apiKey}`,
   144→                    'Content-Type': 'application/json',
   145→                },
   146→                timeout: 15000,
   147→            },
   148→        );
   149→
   150→        const formatted = response.data?.choices?.[0]?.message?.content?.trim();
   151→        return formatted || text;
   152→    }
   153→}
   154→
   155→export const textPostProcessor = new TextPostProcessor();
   156→

