import axios from 'axios';
import { TranscriptionMode } from '../config/settings';

export interface PostProcessingOptions {
    autoCapitalize: boolean;
    fixPunctuation: boolean;
    removeFillers: boolean;
    systemPrompt: string;
}

// Common filler words/phrases to strip
const FILLER_PATTERNS = [
    /\b(um|uh|er|ah|euh|bah|ben|bref|genre|en fait|du coup|voilà|quoi|tu vois|you know|basically|actually|literally|I mean|so yeah|right|like)\b/gi,
];

// System prompts for each transcription mode
const MODE_PROMPTS: Record<TranscriptionMode, string> = {
    raw: '', // no processing
    clean: '', // local processing only, no GPT
    rewrite: `Tu es un assistant d'écriture professionnel. Reformule le texte dicté en prose professionnelle, claire et structurée. Conserve le sens exact. Corrige la grammaire, la ponctuation, et retire les hésitations. Si le texte est un email, formate-le comme tel avec salutation et conclusion. Réponds UNIQUEMENT avec le texte reformulé, sans commentaire.`,
};

/**
 * Text post-processing pipeline for transcriptions.
 * Supports 3 modes: raw, clean, rewrite
 */
class TextPostProcessor {
    /**
     * Process transcript based on mode
     */
    async processWithMode(
        text: string,
        apiKey: string,
        mode: TranscriptionMode,
        options: Partial<PostProcessingOptions> = {},
    ): Promise<string> {
        if (!text.trim()) return text;

        // RAW mode: return as-is
        if (mode === 'raw') {
            return text.trim();
        }

        // CLEAN mode: local processing only
        if (mode === 'clean') {
            return this.processLocal(text, options);
        }

        // REWRITE mode: local clean + GPT rewrite
        if (mode === 'rewrite') {
            const cleaned = this.processLocal(text, options);
            const prompt = options.systemPrompt || MODE_PROMPTS.rewrite;
            if (prompt && apiKey) {
                try {
                    return await this.gptFormat(cleaned, apiKey, prompt);
                } catch (err) {
                    console.error('[TextPostProcessor] GPT rewrite failed, using cleaned text:', err);
                    return cleaned;
                }
            }
            return cleaned;
        }

        return text.trim();
    }

    /**
     * Legacy method — backwards compat
     */
    async process(
        text: string,
        apiKey: string,
        options: Partial<PostProcessingOptions> = {},
    ): Promise<string> {
        return this.processLocal(text, options);
    }

    /**
     * Local (no API call) post-processing
     */
    private processLocal(text: string, options: Partial<PostProcessingOptions> = {}): string {
        let result = text.trim();

        if (options.removeFillers !== false) {
            result = this.removeFillers(result);
        }

        if (options.autoCapitalize !== false) {
            result = this.autoCapitalize(result);
        }

        if (options.fixPunctuation !== false) {
            result = this.fixPunctuation(result);
        }

        return result;
    }

    private removeFillers(text: string): string {
        let result = text;
        for (const pattern of FILLER_PATTERNS) {
            result = result.replace(pattern, '');
        }
        return result.replace(/\s{2,}/g, ' ').trim();
    }

    private autoCapitalize(text: string): string {
        let result = text.charAt(0).toUpperCase() + text.slice(1);
        result = result.replace(/([.!?]\s+)([a-z])/g, (_, punct, letter) => {
            return punct + letter.toUpperCase();
        });
        return result;
    }

    private fixPunctuation(text: string): string {
        let result = text;
        result = result.replace(/\s+([.,!?;:])/g, '$1');
        result = result.replace(/([.,!?;:])([A-Za-zÀ-ÿ])/g, '$1 $2');
        if (result.length > 0 && !/[.!?]$/.test(result)) {
            result += '.';
        }
        return result;
    }

    private async gptFormat(
        text: string,
        apiKey: string,
        systemPrompt: string,
    ): Promise<string> {
        const response = await axios.post(
            'https://api.openai.com/v1/chat/completions',
            {
                model: 'gpt-4o-mini',
                messages: [
                    { role: 'system', content: systemPrompt },
                    { role: 'user', content: text },
                ],
                temperature: 0.3,
                max_tokens: 2048,
            },
            {
                headers: {
                    Authorization: `Bearer ${apiKey}`,
                    'Content-Type': 'application/json',
                },
                timeout: 15000,
            },
        );

        const formatted = response.data?.choices?.[0]?.message?.content?.trim();
        return formatted || text;
    }
}

export const textPostProcessor = new TextPostProcessor();

