/**
 * Inject text into the application that had focus when recording started.
 * @param targetApp  macOS process name captured before the overlay appeared
 */
async injectText(text: string, targetApp?: string): Promise<void> {
    try {
        await this.pasteViaClipboard(text, targetApp);
        console.log('[TextInjection] Injected', text.length, 'chars');
    } catch (error) {
        console.error('[TextInjection] Failed:', error);
        throw new Error('Failed to insert text into application');
    }
}

/**
 * Paste text via clipboard:
 * 1. Activate the target app (macOS only) so focus is correct
 * 2. Write to clipboard
 * 3. Simulate Cmd+V / Ctrl+V
 * 4. Restore previous clipboard
 */
private async pasteViaClipboard(text: string, targetApp?: string): Promise<void> {
    const { clipboard } = await import('electron');
    const previousClipboard = clipboard.readText();

    try {
        if (process.platform === 'darwin') {
            // Explicitly activate the target app before pasting
            if (targetApp) {
                const safeApp = targetApp.replace(/\\/g, '\\\\').replace(/"/g, '\\"');
                try {
                    execSync(`osascript -e 'tell application "${safeApp}" to activate'`);
                    await this.delay(120); // wait for activation
                } catch { /* app might not be scriptable — proceed anyway */ }
            }

            clipboard.writeText(text);
            await this.delay(50);
            execSync(`osascript -e 'tell application "System Events" to keystroke "v" using {command down}'`);
        } else {
            // Windows / Linux: use robotjs
            clipboard.writeText(text);
            await this.delay(50);
            const robot = (await import('robotjs')).default;
            robot.keyTap('v', 'control');
        }

        await this.delay(150);
        clipboard.writeText(previousClipboard);
    } catch (error) {
        clipboard.writeText(previousClipboard);
        throw error;
    }
}

