/**
 * Audio capture for Renderer process (Web Audio API)
 */

export const AUDIO_SAMPLE_RATE = 24000;

class AudioCapture {
    private mediaStream: MediaStream | null = null;
    private audioContext: AudioContext | null = null;
    private analyser: AnalyserNode | null = null;
    private scriptProcessor: ScriptProcessorNode | null = null;
    private visualizationData: Uint8Array = new Uint8Array(128);
    private isRecording = false;
    private onPcmChunk: ((chunk: ArrayBuffer) => void) | null = null;

    constructor() {
        // Initialize visualization data
        this.visualizationData = new Uint8Array(128);
    }

    /**
     * Set callback for PCM chunks
     */
    setOnPcmChunk(callback: (chunk: ArrayBuffer) => void) {
        this.onPcmChunk = callback;
    }

    /**
     * Start audio recording with PCM streaming
     */
    async startRecording(): Promise<void> {
        if (this.isRecording) return;

        try {
            // Request microphone access
            this.mediaStream = await navigator.mediaDevices.getUserMedia({
                audio: {
                    channelCount: 1,
                    sampleRate: AUDIO_SAMPLE_RATE,
                    echoCancellation: true,
                    noiseSuppression: true,
                    autoGainControl: true,
                },
            });

            // Setup audio context
            this.audioContext = new AudioContext({ sampleRate: AUDIO_SAMPLE_RATE });
            const source = this.audioContext.createMediaStreamSource(this.mediaStream);

            // Analyser for UI visualization
            this.analyser = this.audioContext.createAnalyser();
            this.analyser.fftSize = 256;
            this.analyser.smoothingTimeConstant = 0.8;
            source.connect(this.analyser);

            // ScriptProcessor to capture raw PCM samples for streaming
            // Buffer size 4096 ≈ 170ms at 24kHz
            const bufferSize = 4096;
            this.scriptProcessor = this.audioContext.createScriptProcessor(bufferSize, 1, 1);

            this.scriptProcessor.onaudioprocess = (event) => {
                if (!this.isRecording) return;

                const inputData = event.inputBuffer.getChannelData(0); // Float32 [-1, 1]

                // Convert Float32 -> Int16LE PCM
                const pcmBuffer = new Int16Array(inputData.length);
                for (let i = 0; i < inputData.length; i++) {
                    const sample = Math.max(-1, Math.min(1, inputData[i]));
                    pcmBuffer[i] = sample < 0 ? sample * 0x8000 : sample * 0x7FFF;
                }

                if (this.onPcmChunk) {
                    this.onPcmChunk(pcmBuffer.buffer as ArrayBuffer);
                }
            };

            source.connect(this.scriptProcessor);
            this.scriptProcessor.connect(this.audioContext.destination);

            this.isRecording = true;
            this.updateVisualizationLoop();

            console.log('Audio recording started (Renderer)');
        } catch (error) {
            console.error('Failed to start audio recording:', error);
            throw error;
        }
    }

    /**
     * Stop recording
     */
    stopRecording(): void {
        this.isRecording = false;

        if (this.mediaStream) {
            this.mediaStream.getTracks().forEach(track => track.stop());
            this.mediaStream = null;
        }

        if (this.scriptProcessor) {
            this.scriptProcessor.disconnect();
            this.scriptProcessor = null;
        }

        if (this.analyser) {
            this.analyser.disconnect();
            this.analyser = null;
        }

        if (this.audioContext) {
            this.audioContext.close();
            this.audioContext = null;
        }
    }

    /**
     * Visualization loop
     */
    private updateVisualizationLoop() {
        if (!this.isRecording || !this.analyser) return;

        this.analyser.getByteFrequencyData(this.visualizationData);
        requestAnimationFrame(() => this.updateVisualizationLoop());
    }

    /**
     * Get current visualization data
     */
    getVisualizationData(): Uint8Array {
        return this.visualizationData;
    }
}

export const audioCapture = new AudioCapture();

